/**
 * @file test_validation.cu
 * @brief Validation tests comparing GANSU results against PySCF reference values.
 *
 * Reference values generated by script/validate_with_pyscf.py
 * PySCF settings: conv_tol=1e-12, cart=True for cc-pVDZ
 */

#include <gtest/gtest.h>
#include "builder.hpp"
#include "parameter_manager.hpp"
#include <iomanip>
#include <sstream>

using namespace gansu;

// ============================================================
//  PySCF reference values
// ============================================================

// RHF / STO-3G
constexpr real_t REF_H2_RHF_STO3G = -1.1175058842;
constexpr real_t REF_H2O_RHF_STO3G = -74.9659011616;
constexpr real_t REF_NH3_RHF_STO3G = -55.4554193875;
constexpr real_t REF_CH4_RHF_STO3G = -39.7268629038;
constexpr real_t REF_N2_RHF_STO3G = -107.5006541881;
constexpr real_t REF_HF_RHF_STO3G = -98.5728469737;

// RHF / cc-pVDZ (Cartesian)
constexpr real_t REF_H2O_RHF_ccpVDZ = -76.0234907752;

// UHF / STO-3G
constexpr real_t REF_O2_UHF_STO3G = -147.6364161566; // PySCF stability-optimized

// ROHF / STO-3G
constexpr real_t REF_O2_ROHF_STO3G = -147.6324148786;

// Post-HF / H2O / STO-3G
constexpr real_t REF_H2O_MP2_STO3G_corr = -0.0389637139;
constexpr real_t REF_H2O_CCSD_STO3G_corr = -0.0543962594;
constexpr real_t REF_H2O_CCSDT_STO3G_total = -75.0203643861;
constexpr real_t REF_H2O_FCI_STO3G_corr = -0.0545225877;

// RHF / cc-pVDZ (Cartesian) - additional molecules with d-functions
constexpr real_t REF_NH3_RHF_ccpVDZ = -56.1943219246;
constexpr real_t REF_CH4_RHF_ccpVDZ = -40.1985958587;

// Post-HF / H2O / cc-pVDZ (Cartesian)
constexpr real_t REF_H2O_MP2_ccpVDZ_corr = -0.2102563512;
constexpr real_t REF_H2O_CCSD_ccpVDZ_corr = -0.2192016272;
constexpr real_t REF_H2O_CCSDT_ccpVDZ_total = -76.2461303362;

// RHF / cc-pVTZ (Cartesian) - f-functions
constexpr real_t REF_H2O_RHF_ccpVTZ = -76.0531393100;

// Post-HF / H2O / cc-pVTZ (Cartesian)
constexpr real_t REF_H2O_MP2_ccpVTZ_corr = -0.2816708958;
constexpr real_t REF_H2O_CCSD_ccpVTZ_corr = -0.2870700626;
constexpr real_t REF_H2O_CCSDT_ccpVTZ_total = -76.3484466073;

// Post-HF / NH3 / cc-pVDZ (Cartesian)
constexpr real_t REF_NH3_CCSD_ccpVDZ_corr = -0.2097206001;
constexpr real_t REF_NH3_CCSDT_ccpVDZ_total = -56.4082625771;

// Post-HF / HF / cc-pVDZ (Cartesian)
constexpr real_t REF_HFmol_RHF_ccpVDZ = -100.0167900396;
constexpr real_t REF_HFmol_CCSD_ccpVDZ_corr = -0.2139496049;
constexpr real_t REF_HFmol_CCSDT_ccpVDZ_total = -100.2328803182;

// Post-HF / CH4 / cc-pVDZ (Cartesian)
constexpr real_t REF_CH4_CCSD_ccpVDZ_corr = -0.1895739578;
constexpr real_t REF_CH4_CCSDT_ccpVDZ_total = -40.3920273941;

// Tolerances
constexpr real_t TOL_POSTHF_TZ = 2e-5;  // Post-HF tolerance for cc-pVTZ (spin-orbital accumulates more FP error with 2x indices)
constexpr real_t TOL_HF = 1e-6;       // HF total energy tolerance
constexpr real_t TOL_POSTHF = 2e-6;   // Post-HF correlation energy tolerance (STO-3G)
constexpr real_t TOL_POSTHF_DZ = 5e-6; // Post-HF tolerance for cc-pVDZ (larger basis)
constexpr real_t TOL_RI = 2e-3;       // RI approximation tolerance (inherent fitting error)
constexpr real_t TOL_RI_AUTO = 5e-2;  // Auto-generated auxiliary basis tolerance (less accurate than optimized fitting basis)


// ============================================================
//  Helper: run GANSU calculation
// ============================================================

struct GansuResult {
    real_t hf_total_energy;
    real_t post_hf_energy;   // correlation energy (0 if no post-HF)
};

static GansuResult run_gansu(const std::string& xyz,
                              const std::string& basis,
                              const std::string& method,
                              const std::string& post_hf = "none",
                              int charge = 0,
                              int beta_to_alpha = 0,
                              const std::string& initial_guess = "core",
                              const std::string& eri_method = "stored",
                              const std::string& auxiliary_basis = "",
                              int ccsd_algorithm = 0)
{
    // Clear any sticky CUDA errors from previous tests
    cudaDeviceSynchronize();
    cudaGetLastError();

    ParameterManager params;
    params["xyzfilename"] = xyz;
    params["gbsfilename"] = basis;
    params["method"] = method;
    params["post_hf_method"] = post_hf;
    params["convergence_energy_threshold"] = "1e-10";
    params["charge"] = std::to_string(charge);
    params["beta_to_alpha"] = std::to_string(beta_to_alpha);
    params["initial_guess"] = initial_guess;
    params["eri_method"] = eri_method;
    if (!auxiliary_basis.empty()) {
        params["auxiliary_gbsfilename"] = auxiliary_basis;
    }
    if (ccsd_algorithm != 0) {
        params["ccsd_algorithm"] = std::to_string(ccsd_algorithm);
    }

    // Suppress GANSU's verbose output during solve
    std::streambuf* orig_buf = std::cout.rdbuf();
    std::ostringstream null_stream;
    std::cout.rdbuf(null_stream.rdbuf());

    auto hf = HFBuilder::buildHF(params);
    hf->solve();

    // Restore stdout
    std::cout.rdbuf(orig_buf);

    GansuResult result;
    result.hf_total_energy = hf->get_total_energy();
    result.post_hf_energy = hf->get_post_hf_energy();

    std::cout << std::setprecision(10) << std::fixed
              << "  GANSU HF total = " << result.hf_total_energy;
    if (post_hf != "none") {
        std::cout << "  post-HF corr = " << result.post_hf_energy
                  << "  total = " << result.hf_total_energy + result.post_hf_energy;
    }
    std::cout << std::endl;

    return result;
}

// Path prefix (test runs from test/build/)
static const std::string XYZ = "../xyz/";
static const std::string BASIS = "../basis/";
static const std::string AUX_BASIS = "../auxiliary_basis/";


// ============================================================
//  RHF / STO-3G
// ============================================================

TEST(ValidationRHF, H2_STO3G) {
    auto r = run_gansu(XYZ + "H2.xyz", BASIS + "sto-3g.gbs", "rhf");
    EXPECT_NEAR(r.hf_total_energy, REF_H2_RHF_STO3G, TOL_HF);
}

TEST(ValidationRHF, H2O_STO3G) {
    auto r = run_gansu(XYZ + "H2O.xyz", BASIS + "sto-3g.gbs", "rhf");
    EXPECT_NEAR(r.hf_total_energy, REF_H2O_RHF_STO3G, TOL_HF);
}

