// ============================================================
//  Benchmark: CCSD algorithm comparison (3 implementations)
//  Algorithm 0 = spatial-optimized (GPU DGEMM + sub-blocks)
//  Algorithm 1 = spatial-naive (no GPU, no sub-blocks)
//  Algorithm 2 = spin-orbital (legacy)
// ============================================================

// --- H2O / STO-3G / CCSD ---

TEST(BenchmarkCCSD, H2O_STO3G_SpatialOptimized) {
    auto r = run_gansu(XYZ + "H2O.xyz", BASIS + "sto-3g.gbs", "rhf",
                       "ccsd", 0, 0, "core", "stored", "", 0);
    EXPECT_NEAR(r.hf_total_energy, REF_H2O_RHF_STO3G, TOL_HF);
    EXPECT_NEAR(r.post_hf_energy, REF_H2O_CCSD_STO3G_corr, TOL_POSTHF);
}

TEST(BenchmarkCCSD, H2O_STO3G_SpatialNaive) {
    auto r = run_gansu(XYZ + "H2O.xyz", BASIS + "sto-3g.gbs", "rhf",
                       "ccsd", 0, 0, "core", "stored", "", 1);
    EXPECT_NEAR(r.hf_total_energy, REF_H2O_RHF_STO3G, TOL_HF);
    EXPECT_NEAR(r.post_hf_energy, REF_H2O_CCSD_STO3G_corr, TOL_POSTHF);
}

TEST(BenchmarkCCSD, H2O_STO3G_SpinOrbital) {
    auto r = run_gansu(XYZ + "H2O.xyz", BASIS + "sto-3g.gbs", "rhf",
                       "ccsd", 0, 0, "core", "stored", "", 2);
    EXPECT_NEAR(r.hf_total_energy, REF_H2O_RHF_STO3G, TOL_HF);
    EXPECT_NEAR(r.post_hf_energy, REF_H2O_CCSD_STO3G_corr, TOL_POSTHF);
}

